boolean isPalindrome(String s){
  String c = s.toLowerCase().replaceAll("[^a-z0-9]","");
  return c.equals(new StringBuilder(c).reverse().toString());
}

Character firstUnique(String s){
  Map<Character,Long> m = s.chars().mapToObj(c->(char)c)
     .collect(Collectors.groupingBy(c->c, LinkedHashMap::new, Collectors.counting()));
  return m.entrySet().stream().filter(e->e.getValue()==1)
     .map(Map.Entry::getKey).findFirst().orElse(null);
}

boolean isAnagram(String a,String b){
  char[] x=a.toCharArray(), y=b.toCharArray();
  Arrays.sort(x); Arrays.sort(y);
  return Arrays.equals(x,y);
}

int[] twoSum(int[] nums,int target){
  Map<Integer,Integer> seen=new HashMap<>();
  for(int i=0;i<nums.length;i++){
    int need=target-nums[i];
    if(seen.containsKey(need)) return new int[]{seen.get(need),i};
    seen.put(nums[i],i);
  }
  return new int[]{};
}

class IdempotencyTracker{
  private final Set<String> seen = ConcurrentHashMap.newKeySet();
  boolean register(String key){ return seen.add(key); } // true = новый
}

