package db;
import java.math.BigDecimal;
import java.sql.*;

public class DbClient {
  private static final String URL="jdbc:postgresql://localhost:5432/postgres";
  public static BigDecimal getBalance(String id) throws SQLException {
    try(Connection c=DriverManager.getConnection(URL,"postgres","postgres");
        PreparedStatement ps=c.prepareStatement("SELECT balance FROM accounts WHERE id=?::uuid")){
      ps.setString(1,id); ResultSet rs=ps.executeQuery(); rs.next();
      return rs.getBigDecimal("balance");
    }
  }
  public static int countTxByKey(String key) throws SQLException {
    try(Connection c=DriverManager.getConnection(URL,"postgres","postgres");
        PreparedStatement ps=c.prepareStatement("SELECT COUNT(*) FROM transactions WHERE idempotency_key=?")){
      ps.setString(1,key); ResultSet rs=ps.executeQuery(); rs.next();
      return rs.getInt(1);
    }
  }
}

