package tests;
import config.BaseTest; import db.DbClient;
import org.junit.jupiter.api.Test;
import java.math.BigDecimal; import java.util.UUID;
import static io.restassured.RestAssured.given;
import static org.hamcrest.Matchers.*;
import static org.assertj.core.api.Assertions.assertThat;

class TransferPositiveTest extends BaseTest {
  @Test
  void successfulTransfer() throws Exception {
    String src="83740e53-609c-4822-9213-4f9e61f22401";
    String dst="11259624-5f5c-4830-9973-77405085440a";
    BigDecimal before=DbClient.getBalance(src);
    String body="""
      {\"source_account_id\":\"%s\",\"destination_account_id\":\"%s\",
       \"amount\":1500.50,\"currency\":\"USD\",\"description\":\"rent\",\"save_as_template\":true}
      """.formatted(src,dst);
    given().header("Idempotency-Key",UUID.randomUUID().toString())
           .header("Authorization","Bearer valid-token")
           .contentType("application/json").body(body)
    .when().post("/api/v1/transfers/internal")
    .then().statusCode(200)
           .body("status",equalTo("success"))
           .body("transaction_id",notNullValue());
    assertThat(DbClient.getBalance(src))
        .isEqualByComparingTo(before.subtract(new BigDecimal("1500.50")));
  }
}

