package tests;
import config.BaseTest; import db.DbClient;
import org.junit.jupiter.api.Test; import io.restassured.response.Response;
import java.util.UUID;
import static io.restassured.RestAssured.given;
import static org.assertj.core.api.Assertions.assertThat;

class IdempotencyTest extends BaseTest {
  Response send(String key){
    return given().header("Idempotency-Key",key)
      .header("Authorization","Bearer valid-token")
      .contentType("application/json")
      .body("{\"source_account_id\":\"83740e53-609c-4822-9213-4f9e61f22401\",\"destination_account_id\":\"11259624-5f5c-4830-9973-77405085440a\",\"amount\":10,\"currency\":\"USD\"}")
      .post("/api/v1/transfers/internal");
  }
  @Test void sameKeyOneTransaction() throws Exception {
    String key=UUID.randomUUID().toString();
    Response a=send(key), b=send(key);
    assertThat(b.jsonPath().getString("transaction_id"))
        .isEqualTo(a.jsonPath().getString("transaction_id"));
    assertThat(DbClient.countTxByKey(key)).isEqualTo(1);
  }
}

